use rusoto_core::{client::Client, config::Config};
use rusoto_dynamodb::{DynamoDbClient, Table};

fn main() {
    let config = Config::builder()
        .region("us-east-1")
        .build()?;

    let client = DynamoDbClient::builder()
        .region(config.region())
        .build()?;

    let table = Table::builder()
        .table_name("ports")
        .build()?;

    let params = table
        .put_item(
            PutItemInput {
                item: serde_json::json!({
                    "name": "test_port",
                    "description": "Test port",
                    "type": "input",
                    "max_value": 65535,
                    "min_value": 1,
                    "default_value": 1,
                    "required": true,
                    "exact_value": 1,
                    "assistant_assistant": "true"
                })
